    @WebMethod
    public String processXMLData(String xmlPayload) {
        try {
            DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
            factory.setNamespaceAware(true);
            factory.setIgnoringElementContentWhitespace(true);
            factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
            
            DocumentBuilder builder = factory.newDocumentBuilder();
            Document document = builder.parse(new ByteArrayInputStream(xmlPayload.getBytes()));
            
            return processDocument(document);
            
        } catch (ParserConfigurationException | SAXException | IOException e) {
            throw new RuntimeException("Error processing XML data: " + e.getMessage(), e);
        }
    }
    
    private String processDocument(Document document) {
        Element root = document.getDocumentElement();
        StringBuilder result = new StringBuilder();
        
        processElement(root, result, 0);
        
        return result.toString();
    }
    
    private void processElement(Element element, StringBuilder result, int depth) {
        String indent = "  ".repeat(depth);
        
        result.append(indent).append("<").append(element.getNodeName());
        
        // Process attributes
        if (element.hasAttributes()) {
            for (int i = 0; i < element.getAttributes().getLength(); i++) {
                result.append(" ").append(element.getAttributes().item(i).getNodeName())
                      .append("=\"").append(element.getAttributes().item(i).getNodeValue()).append("\"");
            }
        }
        
        result.append(">");
        
        // Process child elements and text content
        NodeList children = element.getChildNodes();
        boolean hasTextContent = false;
        boolean hasChildElements = false;
        
        for (int i = 0; i < children.getLength(); i++) {
            if (children.item(i).getNodeType() == org.w3c.dom.Node.TEXT_NODE) {
                String text = children.item(i).getNodeValue().trim();
                if (!text.isEmpty()) {
                    hasTextContent = true;
                }
            } else if (children.item(i).getNodeType() == org.w3c.dom.Node.ELEMENT_NODE) {
                hasChildElements = true;
            }
        }
        
        if (hasTextContent && !hasChildElements) {
            for (int i = 0; i < children.getLength(); i++) {
                if (children.item(i).getNodeType() == org.w3c.dom.Node.TEXT_NODE) {
                    result.append(children.item(i).getNodeValue());
                }
            }
        } else {
            result.append("\n");
            for (int i = 0; i < children.getLength(); i++) {
                if (children.item(i).getNodeType() == org.w3c.dom.Node.ELEMENT_NODE) {
                    processElement((Element) children.item(i), result, depth + 1);
                } else if (children.item(i).getNodeType() == org.w3c.dom.Node.TEXT_NODE) {
                    String text = children.item(i).getNodeValue().trim();
                    if (!text.isEmpty()) {
                        result.append("  ".repeat(depth + 1)).append(text).append("\n");
                    }
                }
            }
        }
        
        result.append(indent).append("</").append(element.getNodeName()).append(">\n");
    }
    
    @WebMethod
    public List<ImportRecord> processLargeXMLPayload(String xmlPayload) {
        List<ImportRecord> records = new ArrayList<>();
        
        try {
            DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
            factory.setNamespaceAware(true);
            factory.setIgnoringElementContentWhitespace(true);
            factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
            
            DocumentBuilder builder = factory.newDocumentBuilder();
            Document document = builder.parse(new ByteArrayInputStream(xmlPayload.getBytes()));
            
            NodeList recordNodes = document.getElementsByTagName("record");
            
            for (int i = 0; i < recordNodes.getLength(); i++) {
                Element recordElement = (Element) recordNodes.item(i);
                ImportRecord record = new ImportRecord();
                
                record.setId(getElementText(recordElement, "id"));
                record.setName(getElementText(recordElement, "name"));
                record.setEmail(getElementText(recordElement, "email"));
                record.setAddress(getElementText(recordElement, "address"));
                
                // Process nested entities
                NodeList nestedElements = recordElement.getChildNodes();
                for (int j = 0; j < nestedElements.getLength(); j++) {
                    if (nestedElements.item(j).getNodeType() == org.w3c.dom.Node.ELEMENT_NODE) {
                        Element nestedElement = (Element) nestedElements.item(j);
                        String elementName = nestedElement.getNodeName();
                        
                        if ("metadata".equals(elementName)) {
                            record.setMetadata(processMetadata(nestedElement));
                        } else if ("attachments".equals(elementName)) {
                            record.setAttachments(processAttachments(nestedElement));
                        } else if ("relatedRecords".equals(elementName)) {
                            record.setRelatedRecords(processRelatedRecords(nestedElement));
                        }
                    }
                }
                
                records.add(record);
            }
            
        } catch (ParserConfigurationException | SAXException | IOException e) {
            throw new RuntimeException("Error processing large XML payload: " + e.getMessage(), e);
        }
        
        return records;
    }
    
    private String getElementText(Element parent, String elementName) {
        NodeList nodeList = parent.getElementsByTagName(elementName);
        if (nodeList.getLength() > 0) {
            return nodeList.item(0).getTextContent();
        }
        return null;
    }
    
